PRAGMA defer_foreign_keys=TRUE;
CREATE TABLE students (
  id TEXT PRIMARY KEY,
  name TEXT NOT NULL,
  school_name TEXT,
  grade TEXT,
  status TEXT DEFAULT '재원',
  created_at DATETIME DEFAULT CURRENT_TIMESTAMP,
  updated_at DATETIME DEFAULT CURRENT_TIMESTAMP
, memo TEXT, guardian_name TEXT, guardian_relation TEXT, student_phone TEXT, parent_phone TEXT, student_pin TEXT, target_score INTEGER DEFAULT NULL, planner_exam_date TEXT);
CREATE TABLE classes (
  id TEXT PRIMARY KEY,
  name TEXT NOT NULL,
  grade TEXT,
  subject TEXT,
  teacher_name TEXT
, schedule_days TEXT, is_active INTEGER DEFAULT 1, textbook TEXT DEFAULT '', day_group TEXT, time_label TEXT);
CREATE TABLE class_students (
  class_id TEXT NOT NULL,
  student_id TEXT NOT NULL,
  PRIMARY KEY (class_id, student_id)
);
CREATE TABLE attendance (
  id TEXT PRIMARY KEY,
  student_id TEXT NOT NULL,
  status TEXT NOT NULL,
  date DATE NOT NULL,
  created_at DATETIME DEFAULT CURRENT_TIMESTAMP
);
CREATE TABLE homework (
  id TEXT PRIMARY KEY,
  student_id TEXT NOT NULL,
  status TEXT NOT NULL,
  date DATE NOT NULL,
  created_at DATETIME DEFAULT CURRENT_TIMESTAMP
);
CREATE TABLE exam_sessions (
  id TEXT PRIMARY KEY,
  student_id TEXT NOT NULL,
  exam_title TEXT,
  score INTEGER,
  exam_date DATE,
  updated_at DATETIME DEFAULT CURRENT_TIMESTAMP
, question_count INTEGER DEFAULT 0, class_id TEXT, archive_file TEXT);
CREATE TABLE wrong_answers (
  id INTEGER PRIMARY KEY AUTOINCREMENT,
  session_id TEXT NOT NULL,
  question_id TEXT NOT NULL,
  student_id TEXT NOT NULL
);
CREATE TABLE questions (
  id TEXT PRIMARY KEY,
  standard_unit TEXT,
  difficulty TEXT
);
CREATE TABLE consultations (
  id TEXT PRIMARY KEY,
  student_id TEXT NOT NULL,
  date TEXT NOT NULL,
  type TEXT,
  content TEXT NOT NULL,
  next_action TEXT,
  created_at DATETIME DEFAULT CURRENT_TIMESTAMP
);
CREATE TABLE operation_memos (
  id TEXT PRIMARY KEY,
  memo_date TEXT NOT NULL,
  content TEXT NOT NULL,
  is_pinned INTEGER DEFAULT 0,
  is_done INTEGER DEFAULT 0,
  created_at DATETIME DEFAULT CURRENT_TIMESTAMP
, teacher_name TEXT DEFAULT '');
CREATE TABLE exam_schedules (
  id TEXT PRIMARY KEY,
  school_name TEXT NOT NULL,
  grade TEXT,
  exam_name TEXT,
  exam_date TEXT NOT NULL,
  memo TEXT,
  created_at DATETIME DEFAULT CURRENT_TIMESTAMP
);
CREATE TABLE teachers (
  id TEXT PRIMARY KEY,
  name TEXT NOT NULL,
  login_id TEXT UNIQUE NOT NULL,
  password_hash TEXT NOT NULL,
  role TEXT DEFAULT 'teacher',
  created_at DATETIME DEFAULT CURRENT_TIMESTAMP
);
CREATE TABLE teacher_classes (
  teacher_id TEXT NOT NULL,
  class_id TEXT NOT NULL,
  PRIMARY KEY (teacher_id, class_id)
);
CREATE TABLE exam_blueprints (
  archive_file TEXT NOT NULL,
  question_no INTEGER NOT NULL,
  source_archive_file TEXT NOT NULL,
  source_question_no INTEGER NOT NULL,
  standard_unit_key TEXT,
  standard_unit TEXT,
  standard_course TEXT,
  concept_cluster_key TEXT,
  created_at TEXT DEFAULT CURRENT_TIMESTAMP,
  updated_at TEXT DEFAULT CURRENT_TIMESTAMP,
  PRIMARY KEY (archive_file, question_no)
);
CREATE TABLE class_exam_assignments (
  id TEXT PRIMARY KEY,
  class_id TEXT NOT NULL,
  exam_title TEXT NOT NULL,
  exam_date TEXT NOT NULL,
  question_count INTEGER DEFAULT 0,
  archive_file TEXT DEFAULT '',
  source_type TEXT DEFAULT 'archive',
  created_at TEXT DEFAULT CURRENT_TIMESTAMP,
  updated_at TEXT DEFAULT CURRENT_TIMESTAMP,
  UNIQUE(class_id, exam_title, exam_date, archive_file)
);
CREATE TABLE daily_journals (
  id TEXT PRIMARY KEY,
  date TEXT NOT NULL,
  teacher_name TEXT NOT NULL,
  content TEXT NOT NULL,
  status TEXT DEFAULT '작성중',
  feedback TEXT DEFAULT '',
  created_at DATETIME DEFAULT CURRENT_TIMESTAMP,
  updated_at DATETIME DEFAULT CURRENT_TIMESTAMP
);
CREATE TABLE class_textbooks (id TEXT PRIMARY KEY, class_id TEXT NOT NULL, title TEXT NOT NULL, status TEXT DEFAULT 'active', start_date TEXT, end_date TEXT, sort_order INTEGER DEFAULT 0, created_at DATETIME DEFAULT CURRENT_TIMESTAMP, updated_at DATETIME DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE class_daily_records (id TEXT PRIMARY KEY, class_id TEXT NOT NULL, date TEXT NOT NULL, teacher_name TEXT, special_note TEXT DEFAULT '', created_at DATETIME DEFAULT CURRENT_TIMESTAMP, updated_at DATETIME DEFAULT CURRENT_TIMESTAMP, UNIQUE(class_id, date));
CREATE TABLE class_daily_progress (id TEXT PRIMARY KEY, record_id TEXT NOT NULL, class_id TEXT NOT NULL, textbook_id TEXT, textbook_title_snapshot TEXT NOT NULL, progress_text TEXT DEFAULT '', created_at DATETIME DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE academy_schedules (
  id TEXT PRIMARY KEY,
  schedule_type TEXT NOT NULL,
  title TEXT NOT NULL,
  schedule_date TEXT NOT NULL,
  start_time TEXT,
  end_time TEXT,
  target_scope TEXT DEFAULT 'global',
  student_id TEXT,
  teacher_name TEXT,
  memo TEXT,
  is_closed INTEGER DEFAULT 0,
  is_deleted INTEGER DEFAULT 0,
  created_at DATETIME DEFAULT CURRENT_TIMESTAMP,
  updated_at DATETIME DEFAULT CURRENT_TIMESTAMP
);
CREATE TABLE school_exam_records (
  id TEXT PRIMARY KEY,
  student_id TEXT NOT NULL,
  class_id TEXT,
  school_name TEXT,
  grade TEXT,
  exam_year INTEGER NOT NULL,
  semester TEXT,
  exam_type TEXT NOT NULL,
  subject TEXT NOT NULL,
  score INTEGER,
  target_score_snapshot INTEGER,
  memo TEXT,
  is_deleted INTEGER DEFAULT 0,
  created_at DATETIME DEFAULT CURRENT_TIMESTAMP,
  updated_at DATETIME DEFAULT CURRENT_TIMESTAMP
);
CREATE TABLE student_plans (
  id TEXT PRIMARY KEY,
  student_id TEXT NOT NULL,
  plan_date TEXT NOT NULL,
  title TEXT NOT NULL,
  subject TEXT,
  is_done INTEGER DEFAULT 0,
  repeat_rule TEXT,
  created_at TEXT DEFAULT (datetime('now','localtime')),
  updated_at TEXT DEFAULT (datetime('now','localtime')),
  FOREIGN KEY (student_id) REFERENCES students(id)
);
CREATE TABLE planner_feedback (
  id TEXT PRIMARY KEY,
  student_id TEXT NOT NULL,
  feedback_date TEXT NOT NULL,
  teacher_comment TEXT,
  badge TEXT,
  completion_rate INTEGER,
  created_at TEXT DEFAULT (datetime('now','localtime')),
  updated_at TEXT DEFAULT (datetime('now','localtime')),
  FOREIGN KEY (student_id) REFERENCES students(id)
);
DELETE FROM sqlite_sequence;
CREATE INDEX idx_consultations_student_id ON consultations(student_id);
CREATE INDEX idx_consultations_date ON consultations(date);
CREATE INDEX idx_operation_memos_date ON operation_memos(memo_date);
CREATE INDEX idx_operation_memos_done ON operation_memos(is_done);
CREATE INDEX idx_exam_schedules_date ON exam_schedules(exam_date);
CREATE INDEX idx_exam_schedules_school ON exam_schedules(school_name);
CREATE INDEX idx_tcls_teacher ON teacher_classes(teacher_id);
CREATE UNIQUE INDEX idx_students_student_pin ON students(student_pin) WHERE student_pin IS NOT NULL AND student_pin != '';
CREATE INDEX idx_exam_blueprints_archive_file ON exam_blueprints(archive_file);
CREATE INDEX idx_exam_blueprints_standard_unit_key ON exam_blueprints(standard_unit_key);
CREATE INDEX idx_exam_blueprints_concept_cluster_key ON exam_blueprints(concept_cluster_key);
CREATE INDEX idx_class_exam_assignments_class
ON class_exam_assignments(class_id);
CREATE INDEX idx_class_exam_assignments_date
ON class_exam_assignments(exam_date);
CREATE INDEX idx_daily_journals_date ON daily_journals(date);
CREATE INDEX idx_daily_journals_teacher ON daily_journals(teacher_name);
CREATE INDEX idx_class_textbooks_class_id ON class_textbooks(class_id);
CREATE INDEX idx_class_textbooks_status ON class_textbooks(status);
CREATE INDEX idx_class_textbooks_class_status ON class_textbooks(class_id, status);
CREATE INDEX idx_class_daily_records_class_date ON class_daily_records(class_id, date);
CREATE INDEX idx_class_daily_records_date ON class_daily_records(date);
CREATE INDEX idx_class_daily_progress_class_id ON class_daily_progress(class_id);
CREATE INDEX idx_class_daily_progress_textbook_id ON class_daily_progress(textbook_id);
CREATE INDEX idx_plans_student_date
  ON student_plans(student_id, plan_date);
CREATE INDEX idx_planner_feedback_student_date
  ON planner_feedback(student_id, feedback_date);
CREATE UNIQUE INDEX idx_planner_feedback_unique_student_date
  ON planner_feedback(student_id, feedback_date);
